{action_set_definitions}: {
  "get_policy_details": {
    "description": "Retrieves the current state of a specific policy, including the base risk score, current status, and document checklist.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy (e.g., POL-5522-XP)."
        }
      },
      "required": [
        "policy_id"
      ]
    },
    "example_output": {
      "policy_id": "POL-5522-XP",
      "risk_score": 45,
      "review_status": "PENDING",
      "document_checklist": [
        "ID_Verified",
        "Financial_Statement_Received"
      ]
    }
  },
  "retrieve_tpa_records": {
    "description": "Fetches the loss development factors and link ratios from the Third Party Administrator (TPA) database for a specific year.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy."
        },
        "year": {
          "type": "integer",
          "description": "The historical year to retrieve records for (e.g., 2021)."
        }
      },
      "required": [
        "policy_id",
        "year"
      ]
    },
    "example_output": {
      "year": 2021,
      "calculated_link_ratio": 1.35
    }
  },
  "update_risk_score": {
    "description": "Updates the internal numerical risk assessment value for the policy application.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy."
        },
        "new_score": {
          "type": "number",
          "description": "The final calculated risk score."
        }
      },
      "required": [
        "policy_id",
        "new_score"
      ]
    },
    "example_output": {
      "success": true,
      "updated_score": 85.5
    }
  },
  "validate_system_integrity": {
    "description": "Checks if all system-enforced data integrity requirements and document checklists are satisfied for a policy before allowing a status change.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy."
        }
      },
      "required": [
        "policy_id"
      ]
    },
    "example_output": {
      "integrity_satisfied": false,
      "missing_requirements": [
        "Data_Integrity_Verified"
      ]
    }
  },
  "normalize_loss_records": {
    "description": "Standardizes disjointed TPA records to ensure consistency and sets the 'Data_Integrity_Verified' requirement to true.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy."
        }
      },
      "required": [
        "policy_id"
      ]
    },
    "example_output": {
      "success": true,
      "message": "Data_Integrity_Verified has been set to true."
    }
  },
  "set_policy_status": {
    "description": "Updates the final review status of the policy (e.g., APPROVED, REJECTED).",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_id": {
          "type": "string",
          "description": "The unique identifier for the policy."
        },
        "status": {
          "type": "string",
          "enum": [
            "APPROVED",
            "REJECTED"
          ],
          "description": "The final underwriting decision."
        }
      },
      "required": [
        "policy_id",
        "status"
      ]
    },
    "example_output": {
      "policy_id": "POL-5522-XP",
      "final_status": "REJECTED"
    }
  }
}
